import React, { useState, useEffect } from "react";
import axios from "axios";

const API_URL = "http://localhost:5000/books"; // JSON Server endpoint

function App() {
  const [books, setBooks] = useState([]);
  const [formData, setFormData] = useState({
    id: "",
    title: "",
    author: "",
    isbn: "",
    status: "Available",
  });
  const [isEditing, setIsEditing] = useState(false);

  // ===== READ =====
  useEffect(() => {
    fetchBooks();
  }, []);

  const fetchBooks = async () => {
    try {
      const response = await axios.get(API_URL);
      setBooks(response.data);
    } catch (error) {
      console.error("Error fetching books", error);
    }
  };

  // ===== HANDLE INPUT =====
  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData({ ...formData, [name]: value });
  };

  // ===== CREATE & UPDATE =====
  const handleSubmit = async (e) => {
    e.preventDefault();

    if (!formData.title || !formData.author || !formData.isbn) {
      alert("Please fill all fields");
      return;
    }

    try {
      if (isEditing) {
        await axios.put(`${API_URL}/${formData.id}`, {
          title: formData.title,
          author: formData.author,
          isbn: formData.isbn,
          status: formData.status,
        });
        setIsEditing(false);
      } else {
        await axios.post(API_URL, {
          title: formData.title,
          author: formData.author,
          isbn: formData.isbn,
          status: formData.status,
        });
      }

      fetchBooks(); 
      resetForm();
    } catch (error) {
      console.error("Error saving book", error);
    }
  };

  // ===== EDIT =====
  const handleEdit = (book) => {
    setFormData({
      id: book.id,
      title: book.title,
      author: book.author,
      isbn: book.isbn,
      status: book.status,
    });
    setIsEditing(true);
  };

  // ===== DELETE =====
  const handleDelete = async (id) => {
    if (window.confirm("Are you sure you want to delete this book?")) {
      try {
        await axios.delete(`${API_URL}/${id}`);
        fetchBooks();
      } catch (error) {
        console.error("Error deleting book", error);
      }
    }
  };

  const resetForm = () => {
    setFormData({
      id: "",
      title: "",
      author: "",
      isbn: "",
      status: "Available",
    });
    setIsEditing(false);
  };

  // ===== STYLING =====
  const containerStyle = {
    maxWidth: "900px",
    margin: "auto",
    padding: "20px",
    fontFamily: "'Segoe UI', Tahoma, Geneva, Verdana, sans-serif",
    backgroundColor: "#f4f7f8",
    borderRadius: "10px",
    boxShadow: "0 5px 15px rgba(0,0,0,0.1)"
  };

  const formStyle = {
    marginBottom: "30px",
    padding: "20px",
    backgroundColor: "#ffffff",
    borderRadius: "8px",
    boxShadow: "0 3px 10px rgba(0,0,0,0.05)"
  };

  const inputStyle = {
    padding: "10px",
    width: "100%",
    borderRadius: "5px",
    border: "1px solid #ccc",
    marginBottom: "15px"
  };

  const buttonStyle = {
    padding: "10px 20px",
    border: "none",
    borderRadius: "5px",
    cursor: "pointer",
    color: "#fff",
    backgroundColor: "#5b4cafff",
    fontWeight: "bold"
  };

  const cancelButtonStyle = {
    ...buttonStyle,
    backgroundColor: "#f44336",
    marginLeft: "10px"
  };

  const tableStyle = {
    width: "100%",
    borderCollapse: "collapse",
    backgroundColor: "#ffffff",
    borderRadius: "8px",
    overflow: "hidden",
    boxShadow: "0 3px 10px rgba(0,0,0,0.05)"
  };

  const thTdStyle = {
    border: "1px solid #ddd",
    padding: "12px",
    textAlign: "left"
  };

  const headerStyle = {
    marginBottom: "20px",
    color: "#333",
    textAlign: "center"
  };

  return (
    <div style={containerStyle}>
      <h1 style={headerStyle}>📚 Library Management System</h1>

      <form onSubmit={handleSubmit} style={formStyle}>
        <h3>{isEditing ? "Edit Book" : "Add Book"}</h3>

        <input
          type="text"
          name="title"
          placeholder="Book Title"
          value={formData.title}
          onChange={handleChange}
          style={inputStyle}
        />

        <input
          type="text"
          name="author"
          placeholder="Author"
          value={formData.author}
          onChange={handleChange}
          style={inputStyle}
        />

        <input
          type="text"
          name="isbn"
          placeholder="ISBN"
          value={formData.isbn}
          onChange={handleChange}
          style={inputStyle}
        />

        <select
          name="status"
          value={formData.status}
          onChange={handleChange}
          style={inputStyle}
        >
          <option value="Available">Available</option>
          <option value="Borrowed">Borrowed</option>
        </select>

        <button type="submit" style={buttonStyle}>
          {isEditing ? "Update Book" : "Add Book"}
        </button>
        {isEditing && (
          <button type="button" onClick={resetForm} style={cancelButtonStyle}>
            Cancel
          </button>
        )}
      </form>

      {/* BOOK LIST */}
      <table style={tableStyle}>
        <thead>
          <tr>
            <th style={thTdStyle}>Title</th>
            <th style={thTdStyle}>Author</th>
            <th style={thTdStyle}>ISBN</th>
            <th style={thTdStyle}>Status</th>
            <th style={thTdStyle}>Actions</th>
          </tr>
        </thead>
        <tbody>
          {books.length === 0 ? (
            <tr>
              <td colSpan="5" align="center" style={thTdStyle}>No books available</td>
            </tr>
          ) : (
            books.map((book) => (
              <tr key={book.id}>
                <td style={thTdStyle}>{book.title}</td>
                <td style={thTdStyle}>{book.author}</td>
                <td style={thTdStyle}>{book.isbn}</td>
                <td style={thTdStyle}>{book.status}</td>
                <td style={thTdStyle}>
                  <button
                    onClick={() => handleEdit(book)}
                    style={{ ...buttonStyle, backgroundColor: "#2196f3", marginRight: "5px" }}
                  >
                    Edit
                  </button>
                  <button
                    onClick={() => handleDelete(book.id)}
                    style={{ ...buttonStyle, backgroundColor: "#f44336" }}
                  >
                    Delete
                  </button>
                </td>
              </tr>
            ))
          )}
        </tbody>
      </table>
    </div>
  );
}

export default App;
